"use client";

import React, { useState } from "react";
import { useParams } from "next/navigation";
import { Upload, X, MapPin, Tag, Info, Calendar } from "lucide-react";
import { lostItems } from "@/app/data/lostitem";
import { foundItems } from "@/app/data/founditem";

const ClaimItemPage = () => {
  const params = useParams();
  const { id } = params;

  const item =
    lostItems.find((it) => String(it.id) === String(id)) ||
    foundItems.find((it) => String(it.id) === String(id));

  const [proofImages, setProofImages] = useState([]);
  const [claimText, setClaimText] = useState("");

  if (!item) return <div className="p-8 text-center">Item not found.</div>;

  const handleFileUpload = (e) => {
    const files = Array.from(e.target.files);
    if (files.length + proofImages.length > 3) {
      alert("You can upload a maximum of 3 images.");
      return;
    }
    setProofImages([...proofImages, ...files]);
  };

  const removeImage = (index) => {
    setProofImages(proofImages.filter((_, i) => i !== index));
  };

  return (
    <div className="max-w-5xl mx-auto p-6 grid md:grid-cols-2 gap-8 min-h-screen">

      {/* LEFT — ITEM INFORMATION */}
      <div className="space-y-4">
        <h1 className="text-3xl font-bold">{item.title}</h1>

        <img
          src={item.image}
          alt={item.title}
          className="w-full rounded-xl shadow"
        />

        <div className="bg-gray-50 p-4 rounded-xl border">
          <h3 className="text-xl font-semibold mb-3 flex items-center">
            <Info className="w-5 h-5 mr-2 text-indigo-600" />
            Item Information
          </h3>

          <p className="text-gray-700 mb-3">{item.description}</p>

          <div className="space-y-2 text-gray-700 text-sm">
            <p className="flex items-center">
              <Tag className="w-4 h-4 mr-2 text-indigo-500" />
              <strong>Category:</strong>&nbsp; {item.category}
            </p>

            <p className="flex items-center">
              <MapPin className="w-4 h-4 mr-2 text-indigo-500" />
              <strong>Location:</strong>&nbsp; {item.location}
            </p>

            <p className="flex items-center">
              <Calendar className="w-4 h-4 mr-2 text-indigo-500" />
              <strong>Date:</strong>&nbsp; {item.date}
            </p>
          </div>
        </div>
      </div>

      {/* RIGHT — CLAIM FORM */}
      <div className="bg-white p-6 rounded-xl shadow border space-y-5">

        <h2 className="text-2xl font-bold">Submit Claim</h2>

        <div>
          <label className="font-semibold block mb-2">
            How can you prove this is your item?
          </label>
          <textarea
            rows={4}
            value={claimText}
            onChange={(e) => setClaimText(e.target.value)}
            className="w-full border rounded-xl p-3"
            placeholder="Write details about your ownership..."
          />
        </div>

        <div>
          <label className="font-semibold block mb-2">
            Upload Proof Photos (Max 3)
          </label>

          <div className="border-2 border-dashed rounded-lg p-4 text-center bg-gray-50">
            <input
              type="file"
              multiple
              accept="image/*"
              onChange={handleFileUpload}
              className="cursor-pointer"
            />
            <p className="text-sm text-gray-600 mt-1">
              Upload clear photos showing proof of ownership.
            </p>
          </div>

          {proofImages.length > 0 && (
            <div className="flex gap-4 flex-wrap mt-3">
              {proofImages.map((file, idx) => (
                <div
                  key={idx}
                  className="relative w-24 h-24 border rounded overflow-hidden"
                >
                  <img
                    src={URL.createObjectURL(file)}
                    className="w-full h-full object-cover"
                  />

                  <button
                    onClick={() => removeImage(idx)}
                    className="absolute top-1 right-1 bg-black/60 text-white p-1 rounded-full"
                  >
                    <X size={14} />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <button className="w-full bg-indigo-600 text-white py-3 rounded-xl font-semibold hover:bg-indigo-700 transition">
          Submit Claim Request
        </button>

      </div>
    </div>
  );
};

export default ClaimItemPage;
